# span-schema-lint: validate staging traces against required schema
import json, sys

REQUIRED_RESOURCE_ATTRS = [
    "service.name", "service.team", "service.version",
    "deployment.environment",
]
REQUIRED_ROOT_SPAN_ATTRS = [
    "agent.use_case",
]
BANNED_ATTR_PATTERNS = ["user.email", "user.name", "patient", "ssn"]

def lint_trace_file(path: str) -> list[str]:
    errors = []
    data = json.load(open(path))
    for resource_span in data.get("resourceSpans", []):
        attrs = {a["key"]: a["value"] for a in resource_span.get("resource", {}).get("attributes", [])}
        for req in REQUIRED_RESOURCE_ATTRS:
            if req not in attrs:
                errors.append(f"Missing resource attribute: {req}")
        for scope_span in resource_span.get("scopeSpans", []):
            for span in scope_span.get("spans", []):
                if span.get("parentSpanId", "") == "":
                    span_attrs = {a["key"]: a["value"] for a in span.get("attributes", [])}
                    for req in REQUIRED_ROOT_SPAN_ATTRS:
                        if req not in span_attrs:
                            errors.append(f"Root span missing: {req}")
                    for banned in BANNED_ATTR_PATTERNS:
                        for key in span_attrs:
                            if banned in key.lower():
                                errors.append(f"Banned attribute pattern '{banned}' in key: {key}")
    return errors

if __name__ == "__main__":
    errs = lint_trace_file(sys.argv[1])
    for e in errs:
        print(f"ERROR: {e}")
    sys.exit(1 if errs else 0)
